        assertTrue(ProcessMiningBridge.offsetOfOcelEventTimestampMs() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelEventAttrCount() >= 0);

        // Test more offsets
        assertTrue(ProcessMiningBridge.offsetOfOcelEventsResultEvents() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelEventsResultCount() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelEventsResultError() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelObjectId() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelObjectType() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelObjectsResultObjects() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelObjectsResultCount() >= 0);
        assertTrue(ProcessMiningBridge.offsetOfOcelObjectsResultError() >= 0);
