        assertEquals("rust4pm_dfg_free", PmCapability.DFG_FREE.getNativeFunctionName());
        assertEquals("Free DFG result", PmCapability.DFG_FREE.getDescription());

        assertEquals("rust4pm_error_free", PmCapability.ERROR_FREE.getNativeFunctionName());
